# write_charts_all.ps1 - run once from inside RAG-BANK:
#     powershell -ExecutionPolicy Bypass -File .\write_charts_all.ps1
$ErrorActionPreference = 'Stop'

$b = ''
$p = Join-Path (Get-Location) 'src/query_clients.py'
$d = Split-Path $p -Parent
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Force -Path $d | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String($b))
Write-Host 'wrote src/query_clients.py' -ForegroundColor Green

$b = ''
$p = Join-Path (Get-Location) 'src/router.py'
$d = Split-Path $p -Parent
if (-not (Test-Path $d)) { New-Item -ItemType Directory -Force -Path $d | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String($b))
Write-Host 'wrote src/router.py' -ForegroundColor Green

